<template>
  <v-container fluid class="pa-6 pt-4 fill-height cctv-api-server-manage">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33" class="d-flex align-center">
        <h3 class="font-weight-bold">{{ $t('aiServerManage') }}</h3>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 33px)" class="pt-0">
        <i-card-top
          :useBtnList="buttonUseList"
          @btnAdd="btnAdd()"
          @btnSearch="btnSearch(true)"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
          class="d-flex mb-0"
        >
          <template #body>
            <v-spacer />
          </template>
        </i-card-top>
        <v-layout column>
          <DxDataGrid
            :key="gridKey"
            id="checkInfoDataGrid"
            class="cctv-api-server-manage-layout-col-height"
            :ref="dxDataGridRef"
            :data-source="cctvApiServerDataSource"
            :remote-operations="false"
            :show-borders="true"
            :show-row-lines="true"
            :column-auto-width="true"
            :allow-column-resizing="true"
            :allow-column-reordering="true"
            :repaint-changes-only="false"
            :focused-row-enabled="true"
            key-expr="server_id"
            @editing-start="onEditingStart"
            @editor-preparing="onEditorPreparing"
            @focused-row-changed="onFocusedRowChanged"
          >
            <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />
            <DxScrolling row-rendering-mode="standard" />
            <DxSelection select-all-mode="allPages" show-check-boxes-mode="always" mode="multiple" />

            <DxColumn data-field="server_id" data-type="string" :caption="$t('serverId')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="server_name" data-type="string" css-class="devest-grid-header-require" :caption="$t('serverNm')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="server_ip" data-type="string" css-class="devest-grid-header-require" :caption="$t('serverIp')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="restapi_port" data-type="string" css-class="devest-grid-header-require" :caption="$t('flaskPort')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="mediamtx_port" data-type="string" css-class="devest-grid-header-require" :caption="$t('mediamtxPort')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="remark" data-type="string" :caption="$t('remark')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="created_at" data-type="string" :caption="$t('createdDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="created_by" data-type="string" :caption="$t('writer')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_at" data-type="string" :caption="$t('updatedDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_by" data-type="string" :caption="$t('modifier')" alignment="center" :visible="true" :allow-editing="false" />
          </DxDataGrid>
        </v-layout>
      </v-sheet>
    </v-row>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue'
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'

import { getUserCd, getCompId } from '@/utils/token'
import { getAiServerList, getAiServer, saveAiServer, deleteAiServer } from '@/api/realTimeVideoSafetyManagement/safetyVideoServerManage.js'

export default {
  mixins: [baseview, BaseDataGrid],
  name: 'SafetyVideoServerManage',
  components: {
  },
  computed: {
    dataGridMain() {
      return this.$refs[this.dxDataGridRef].instance
    },
  },
  data() {
    return {
      gridKey: 0,
      newId: 0,
      dxDataGridRef: 'cctvApiServerDataGridRef',
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      cctvApiServerDataSource: []
    }
  },
  methods: {
    btnAdd() {
      this.newId++
      let newRow = {
        server_id : `NEW_${this.newId}`,
        comp_id : getCompId(),
        mediamtx_port : '',
        remark : '',
        restapi_port : '',
        server_ip : '',
        server_name : '',
        created_at : null,
        created_by : null,
        updated_at : null,
        updated_by : null,
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    btnSearch(isNotify) {
      getAiServerList(isNotify)
        .then(res => {
          this.newId = 0
          this.cctvApiServerDataSource = res.list
        })
    },
    async btnSave() {
      let selectedMainRows = await this.dataGridMain.getSelectedRowsData()
      if (!selectedMainRows.length) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        current => {
          this.dataGridMain.saveEditData()
          if (selectedMainRows.every(el => {
            return el.server_name.trim() == ''
              || el.server_ip.trim() == ''
              || el.restapi_port.trim() == ''
              || el.mediamtx_port.trim() == ''
          })) {
            this.vToastify(`${this.$t('msgReqValidate')},${this.$t('serverNm')},${this.$t('serverIp')},${this.$t('flaskPort')},${this.$t('mediamtxPort')}`, 'warn')
            return
          }
          this.openLoading('saving')
          this.dataGridMain.beginUpdate()
          const param = selectedMainRows.map(el => ({
            ...el,
            userCd: getUserCd()
          }))
          saveAiServer(param, true)
            .then(res => {
              this.btnSearch(false)
            })
            .catch(error => {
              console.error('AI Server Error', error)
            })
            .finally(() => {
              this.dataGridMain.endUpdate()
              this.endLoading()
            })
        },
        null,
        true
      ) 
    },
    async btnDelete() {
      let selectedMainRows = await this.dataGridMain.getSelectedRowsData()
      if (!selectedMainRows.length) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      this.vToastifyPrompt(
        this.$t('doDeleteData'),
        'info',
        current => {
          this.dataGridMain.beginUpdate()
          this.dataGridMain.saveEditData()
          this.openLoading('deleting')
          const param = selectedMainRows.filter(el => !el.__created__)
          const newIds = selectedMainRows.filter(el => el.__created__).map(el => el.server_id)
          this.cctvApiServerDataSource = this.cctvApiServerDataSource.filter(el => !newIds.includes(el.server_id))
          const finishEvent = () => {
            this.dataGridMain.endUpdate()
            this.FocusFirstRow(this.dataGridMain)
            this.endLoading()
          }
          if (param.length !== 0) {
            const deleteParam = param.map(el => el.server_id)
            deleteAiServer(deleteParam, true)
              .then(res => {
                this.btnSearch(false)
              })
              .finally(() => {
                finishEvent()
              })
          } else {
            finishEvent()
          }
        },
        null,
        true
      )
    },
    onEditingStart(e) {

    },
    onFocusedRowChanged(e) {
      
    }
  },
  mounted() {
    this.btnSearch(false)
  },
}
</script>

<style lang="scss">
.cctv-api-server-manage {
  $appBarHeight: 65px;
  $cardTitleHeight: 62px;
  $conditionOneHeight: 46px;
  $paddingHeight: 8px;
  $spare: 3.5vh;
  > div {
    position: relative;
  }
  &-layout-col-height {
    // max-width: 100% !important;
    min-height: calc(100vh - (#{$appBarHeight} + #{$cardTitleHeight} + #{$conditionOneHeight} + (#{$paddingHeight} * 5.8) + #{$spare})) !important;
  }
}
</style>